sql:
SELECT site_name, site_type, site_description
FROM monitoring_sites
WHERE site_type = 'Urban';

external_knowledge:
- "recently" refers to sites installed on or after January 1, 2022;
- "dust and particle pollutants" are categorized under 'particulate matter';
- "high-quality data assessment" indicates an assessment score greater than 80.

- 'urban beacons' refers to sites classified as 'urban';
- 'light up their neighborhoods' metaphorically means monitoring sites are active or in use;
- 'metropolitan zones' refers to CBSA names.

sql:
SELECT site_name
FROM monitoring_sites
WHERE site_type = 'rural';

SELECT site_name, site_type
FROM monitoring_sites
WHERE site_id < 25;

SELECT state_code, AVG(site_elevation) AS average_site_elevation
FROM monitoring_sites
GROUP BY state_code;
